#include <bits/stdc++.h>
using namespace std;

#ifndef ONLINE_JUDGE
#include "./library/debug.cpp"
#else
#define debug(x...)
#define newline()
#endif

#define int long long
using pii = pair<int, int>;
using vi = vector<int>;
using vvi = vector<vi>;
using vpii = vector<pii>;
using vvpii = vector<vector<pii>>;
using vb = vector<bool>;
using vvb = vector<vb>;
#define popcount(a) __builtin_popcountll(a)
const int mod = 1e9 + 7;
#define all(a) a.begin(), a.end()
const char endline = '\n';
int next_int()
{
    int x;
    cin >> x;
    return x;
}
int inv(int i, int m) { return i <= 1 ? i : m - (long long)(m / i) * inv(m % i, m) % m; }

struct Solution
{
    void solve()
    {
        int m, n;
        cin >> m >> n;
        vector<string> vs(m + 1);
        for (auto &s : vs)
            cin >> s;
        int x;
        cin >> x;

        //////////////
        m++, n++;
        int a = -1, b = -1;
        for (int i = 0; i < m && a == -1; i++)
        {
            for (int j = 0; j < n; j++)
            {
                if (vs[i][j] == '*')
                {
                    a = i;
                    b = j;
                    break;
                }
            }
        }

        vector<vvb> visited(m, vvb(n, vb(x + 1, false)));
        queue<tuple<int, int, int, int>> q; // (i, j, current_sum, steps)
        q.push({a, b, 0, 0});
        while (q.empty() == false)
        {
            auto [i, j, current_sum, steps] = q.front();
            q.pop();

            if (i < 0 || i >= m || j < 0 || j >= n || vs[i][j] == '#' || visited[i][j][current_sum])
                continue;

            visited[i][j][current_sum] = true;
            if (vs[i][j] >= '0' && vs[i][j] <= '9')
                current_sum += vs[i][j] - '0';

            if (current_sum > x)
                continue;
            if (current_sum == x)
            {
                cout << steps << endline;
                return;
            }

            q.push({i - 1, j, current_sum, steps + 1});
            q.push({i + 1, j, current_sum, steps + 1});
            q.push({i, j - 1, current_sum, steps + 1});
            q.push({i, j + 1, current_sum, steps + 1});
        }
        cout << -1 << endline;
    }
};

signed main()
{
    #ifndef ONLINE_JUDGE
        freopen("input.txt", "r", stdin);
        freopen("output.txt", "w", stdout);
        freopen("error.txt", "w", stderr);
    #endif
    ios::sync_with_stdio(false);
    cin.tie(NULL);

    int t = 1;
    cin >> t;

    for (int case_no = 1; case_no <= t; case_no++)
    {
        debug(case_no);
        Solution ob;
        ob.solve();
        newline();
    }
    return 0;
}
